import jsonStringify from"json-stringify-deterministic";import{pipe,asyncMap,asyncCollectArray}from"@hyperjump/pact";import*as Browser from"@hyperjump/browser";import*as Instance from"../instance.js";const id="https://json-schema.org/keyword/enum",compile=r=>pipe(Browser.iter(r),asyncMap(Browser.value),asyncMap(jsonStringify),asyncCollectArray),interpret=(r,e)=>{const t=jsonStringify(Instance.value(e));return r.some(r=>t===r)};export default{id:id,compile:compile,interpret:interpret};